    "src/lib.rs": "#[derive(Debug, PartialEq, Eq)]
pub struct Record {
    pub id: String,
    pub kind: String,
    pub value: i32,
    pub tags: Vec<String>,
}

pub fn parse_records(input: &str) -> Result<Vec<Record>, String> {
    let mut out = Vec::new();
    for (idx, raw) in input.lines().enumerate() {
        let line_no = idx + 1;
        let line = raw.trim();
        if line.is_empty() {
            continue;
        }

        let mut id = None;
        let mut kind = None;
        let mut value = None;
        let mut tags = Vec::new();

        for part in line.split('|') {
            let mut kv = part.splitn(2, '=');
            let key = kv.next().unwrap_or("").trim();
            let val = kv.next().unwrap_or("").trim();
            match key {
                "id" => id = Some(val.to_string()),
                "kind" => kind = Some(val.to_string()),
                "value" => {
                    value = Some(
                        val.parse::<i32>()
                            .map_err(|_| format!("line {}: invalid value", line_no))?,
                    )
                }
                "tags" => {
                    if !val.is_empty() {
                        tags = val.split(',').map(|s| s.trim().to_string()).collect();
                    }
                }
                _ => {}
            }
        }

        out.push(Record {
            id: id.unwrap_or_default(),
            kind: kind.unwrap_or_default(),
            value: value.unwrap_or(0),
            tags,
        });
    }
    Ok(out)
}

