        let got = parse_records(input).unwrap();
        assert_eq!(
            got,
            vec![
                Record {
                    id: "A1".into(),
                    kind: "temp".into(),
                    value: 12,
                    tags: vec!["hot".into(), "indoor".into()],
                },
                Record {
                    id: "B2".into(),
                    kind: "humid".into(),
                    value: 0,
                    tags: vec!["lab".into()],
                }
            ]
        );
    }

