    fn rejects_missing_required_fields() {
        let err = parse_records("id=A1|value=3|tags=ok").unwrap_err();
        assert_eq!(err, "line 1: missing required field");

        let err = parse_records("kind=temp|value=3|tags=ok").unwrap_err();
        assert_eq!(err, "line 1: missing required field");

        let err = parse_records("id=A1|kind=temp|tags=ok").unwrap_err();
        assert_eq!(err, "line 1: missing required field");
    }

