    "src/main.rs": "use std::collections::HashMap;

#[derive(Clone, Debug)]
struct Config {
    endpoint: String,
    file: String,
    color: bool,
    retries: u32,
    timeout: u32,
}

#[derive(Default)]
struct PartialConfig {
    endpoint: Option<String>,
    file: Option<String>,
    color: Option<bool>,
    retries: Option<u32>,
    timeout: Option<u32>,
}

fn parse_bool(s: &str) -> Option<bool> {
    match s {
        "1" | "true" | "yes" | "on" => Some(true),
        "0" | "false" | "no" | "off" => Some(false),
        _ => None,
    }
}

fn parse_u32(s: &str) -> Option<u32> {
    s.parse::<u32>().ok()
}

fn from_pairs(pairs: &[(&str, &str)]) -> PartialConfig {
    let mut p = PartialConfig::default();
    for (k, v) in pairs {
        match *k {
            "endpoint" => {
                if !v.is_empty() {
                    p.endpoint = Some((*v).to_string());
                }
            }
            "file" => {
                if !v.is_empty() {
                    p.file = Some((*v).to_string());
                }
            }
            "color" => p.color = parse_bool(v),
            "retries" => p.retries = parse_u32(v),
            "timeout" => p.timeout = parse_u32(v),
            _ => {}
        }
    }
    p
}

fn merge(defaults: Config, env: PartialConfig, file: PartialConfig, cli: PartialConfig) -> Config {
    let mut cfg = defaults;

    if let Some(v) = cli.endpoint.or(file.endpoint).or(env.endpoint) {
        cfg.endpoint = v;
    }
    if let Some(v) = cli.file.or(file.file).or(env.file) {
        cfg.file = v;
    }
    if let Some(v) = cli.color.or(file.color).or(env.color) {
        if v {
            cfg.color = true;
        }
    }
    if let Some(v) = cli.retries.or(file.retries).or(env.retries) {
        if v > 0 {
            cfg.retries = v;
        }
    }
    if let Some(v) = cli.timeout.or(file.timeout).or(env.timeout) {
        if v > 0 {
            cfg.timeout = v;
        }
    }

    cfg
}

fn render(label: &str, cfg: &Config) -> String {
    format!(
        "{} endpoint={} file={} color={} retries={} timeout={}",
        label, cfg.endpoint, cfg.file, cfg.color, cfg.retries, cfg.timeout
    )
}

fn main() {
    let defaults = Config {
        endpoint: "https://default.example".to_string(),
        file: "/tmp/default.log".to_string(),
        color: true,
        retries: 3,
        timeout: 30,
