pub fn select_deployable_lines(packages: &[Package<'_>], env: &str, limit: usize) -> Vec<String> {
    let mut out: Vec<_> = packages
        .iter()
        .filter(|p| !p.archived)
        .filter(|p| !p.name.starts_with("tmp-"))
        .filter(|p| p.downloads >= 100)
        .filter(|p| match env {
