fn summarize(alert: &Alert) -> (&'static str, &'static str, u8) {
    match alert {
        Alert::Incident { code, urgent } => {
            if *urgent {
                ("urgent", "incident", 0)
            } else if *code >= 500 {
                ("incident", "outage", 1)
            } else {
