pub struct RankedPlayer {
    pub rank: usize,
    pub name: String,
    pub total_score: i32,
    pub best_round: i32,
    pub events: usize,
}

pub fn leaderboard(entries: &[(&str, i32)]) -> Vec<RankedPlayer> {
    let mut per_name: HashMap<String, RankedPlayer> = HashMap::new();

    for (name, score) in entries {
        let key = name.to_string();
        let item = per_name.entry(key.clone()).or_insert(RankedPlayer {
            rank: 0,
            name: key,
            total_score: 0,
            best_round: *score,
            events: 0,
        });
        item.total_score += *score;
        if *score > item.best_round {
            item.best_round = *score;
        }
        item.events += 1;
    }

    let mut rows: Vec<RankedPlayer> = per_name.into_values().collect();
    rows.sort_by(|a, b| {
        b.total_score
            .cmp(&a.total_score)
            .then(a.name.cmp(&b.name))
    });

    for (idx, row) in rows.iter_mut().enumerate() {
        row.rank = idx + 1;
    }

    rows
}

