pub fn select_task_titles(tasks: &[Task], owner: &str, limit: usize) -> Vec<&'static str> {
    let mut items: Vec<&Task> = tasks
        .iter()
        .filter(|t| t.active)
        .filter(|t| !t.archived)
        .filter(|t| t.owner == Some(owner))
        .filter(|t| t.estimate <= 8)
