pub struct Entry {
    pub name: String,
    pub id: u32,
    pub kind: String,
    pub active: bool,
}

pub fn parse_entries(input: &str) -> Result<Vec<Entry>, String> {
    let mut out = Vec::new();
    for (idx, raw) in input.lines().enumerate() {
        let line_no = idx + 1;
        let line = raw.trim();
        if line.is_empty() {
            continue;
        }

        let mut name = "";
        let mut id = 0u32;
        let mut kind = "";
        let mut active = false;

        for part in line.split('|') {
            let mut it = part.splitn(2, ':');
            let tag = it.next().unwrap_or("").trim();
            let value = it.next().unwrap_or("").trim();
            match tag {
                "name" => name = value,
                "id" => id = value.parse().unwrap_or(0),
                "kind" => kind = value,
                "active" => active = value == "true",
                _ => {}
            }
        }

        if name.is_empty() || id == 0 {
            return Err(format!("line {} invalid", line_no));
        }

        out.push(Entry {
            name: name.to_string(),
            id,
            kind: kind.to_string(),
            active,
        });
    }
    Ok(out)
}

