        tags: &[&str],
    ) -> Task {
        Task {
            id,
            name: name.to_string(),
            active,
            archived,
            priority,
            score,
            tags: tags.iter().map(|s| s.to_string()).collect(),
        }
    }

    #[test]
    fn sorts_by_score_then_priority_then_name_and_formats_output() {
        let tasks = vec![
            task(1, " Alpha ", true, false, 2, 15, &["ops"]),
