pub struct Record {
    pub kind: String,
    pub id: u32,
    pub value: String,
    pub tags: Vec<String>,
}

pub fn parse_records(input: &str) -> Result<Vec<Record>, String> {
    let mut out = Vec::new();
    for (idx, raw) in input.lines().enumerate() {
        let line_no = idx + 1;
        let line = raw.trim();
        if line.is_empty() {
            continue;
        }

        let mut kind = None;
        let mut id = 0u32;
        let mut value = String::new();
        let mut tags = Vec::new();

        for part in line.split('|') {
            let mut kv = part.splitn(2, '=');
            let key = kv.next().unwrap_or("").trim();
            let val = kv.next().unwrap_or("").trim();
            match key {
                "kind" => kind = Some(val.to_string()),
                "id" => id = val.parse().unwrap_or(0),
                "value" => value = val.to_string(),
                "tags" => {
                    if !val.is_empty() {
                        tags = val.split(',').map(|s| s.trim().to_string()).collect();
                    }
                }
                _ => {}
            }
        }

        if kind.is_none() {
            return Err(format!("line {} missing kind", line_no));
        }

        out.push(Record {
            kind: kind.unwrap(),
            id,
            value,
            tags,
        });
    }
    Ok(out)
}

