#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Sale {
    pub week: u32,
    pub rep: &'static str,
    pub item: &'static str,
    pub units: u32,
    pub amount_cents: i32,
    pub valid: bool,
}

pub fn weekly_summary(rows: &[Sale]) -> String {
    let mut weeks: BTreeMap<u32, (i32, u32, BTreeMap<&'static str, i32>)> = BTreeMap::new();

    for row in rows {
        let entry = weeks
            .entry(row.week)
            .or_insert((0, 0, BTreeMap::new()));
        entry.0 += row.amount_cents;
        entry.1 += 1;
        *entry.2.entry(row.item).or_insert(0) += row.units as i32;
    }

    let mut out = String::new();
    for (week, (amount, rep_count, items)) in weeks {
        out.push_str(&format!("week {}: ${:.2} | reps={}\n", week, amount as f64 / 100.0, rep_count));
        for (item, units) in items {
            out.push_str(&format!("- {}: {}\n", item, units));
        }
    }
    out
}

