    "src/lib.rs": "use std::collections::HashMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub name: String,
    pub score: i32,
    pub attempts: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Ranked {
    pub rank: usize,
    pub name: String,
    pub score: i32,
    pub attempts: u32,
}

pub fn leaderboard(entries: &[Entry]) -> Vec<Ranked> {
    let mut by_name: HashMap<String, Entry> = HashMap::new();
    for e in entries {
        match by_name.get_mut(&e.name) {
            Some(cur) => {
                if e.score >= cur.score {
                    *cur = e.clone();
                }
            }
            None => {
                by_name.insert(e.name.clone(), e.clone());
            }
        }
    }

    let mut rows: Vec<Entry> = by_name.into_values().collect();
    rows.sort_by(|a, b| {
        b.score
            .cmp(&a.score)
            .then(a.attempts.cmp(&b.attempts))
            .then(a.name.cmp(&b.name))
    });

    let mut out = Vec::new();
    for (i, row) in rows.into_iter().enumerate() {
        out.push(Ranked {
            rank: i + 1,
            name: row.name,
            score: row.score,
            attempts: row.attempts,
        });
    }
    out
}

