    "src/lib.rs": "#[derive(Debug, Clone, PartialEq, Eq)]
pub struct EventRecord {
    pub id: String,
    pub kind: String,
    pub value: u32,
    pub tags: Vec<String>,
}

pub fn parse_records(input: &str) -> Result<Vec<EventRecord>, String> {
    let mut out = Vec::new();
    for (idx, raw) in input.lines().enumerate() {
        let line_no = idx + 1;
        let line = raw.trim();
        if line.is_empty() {
            continue;
        }

        let mut id = String::new();
        let mut kind = String::new();
        let mut value = 0u32;
        let mut tags = Vec::new();

        for part in line.split(';') {
            let mut kv = part.splitn(2, '=');
            let key = kv.next().unwrap_or("").trim();
            let val = kv.next().unwrap_or("").trim();
            match key {
                "id" => id = val.to_string(),
                "kind" => kind = val.to_string(),
                "value" => {
                    value = val.parse::<u32>().map_err(|_| format!("line {}: bad value", line_no))?;
                }
                "tags" => {
                    tags = val
                        .split(',')
                        .map(|s| s.trim().to_string())
                        .filter(|s| !s.is_empty())
                        .collect();
                }
                _ => {}
            }
        }

        if id.is_empty() {
            return Err(format!("line {}: missing id", line_no));
        }
        if kind.is_empty() {
            kind = "generic".to_string();
        }

        out.push(EventRecord { id, kind, value, tags });
    }
    Ok(out)
}

