#[derive(Clone, Debug, PartialEq, Eq)]
pub struct MatchRow {
    pub name: &'static str,
    pub points: u32,
    pub wins: u32,
    pub losses: u32,
    pub rounds: u32,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct RankedPlayer {
    pub rank: u32,
    pub name: String,
    pub points: u32,
    pub wins: u32,
    pub losses: u32,
    pub rounds: u32,
}

pub fn leaderboard(rows: &[MatchRow]) -> Vec<RankedPlayer> {
    let mut merged: BTreeMap<String, RankedPlayer> = BTreeMap::new();

    for row in rows {
        merged
            .entry(row.name.to_string())
            .and_modify(|p| {
                p.points += row.points;
                p.wins += row.wins;
                p.losses += row.losses;
                p.rounds += row.rounds;
            })
            .or_insert_with(|| RankedPlayer {
                rank: 0,
                name: row.name.to_string(),
                points: row.points,
                wins: row.wins,
                losses: row.losses,
                rounds: row.rounds,
            });
    }

    let mut out: Vec<RankedPlayer> = merged.into_values().collect();
    out.sort_by(|a, b| {
        b.points
            .cmp(&a.points)
            .then_with(|| b.wins.cmp(&a.wins))
            .then_with(|| a.name.cmp(&b.name))
    });

    for (idx, p) in out.iter_mut().enumerate() {
        p.rank = (idx as u32) + 1;
    }

    out
}

