    "src/main.rs": "enum Action {
    Sync,
    Cleanup,
    Backup,
    Export,
    Notify,
    Report,
}

struct Job {
    action: Action,
    urgent: bool,
    blocked: bool,
    manual: bool,
    retries: u8,
    label: &'static str,
}

fn action_name(action: &Action) -> &'static str {
    match action {
        Action::Sync => "sync",
        Action::Cleanup => "cleanup",
        Action::Backup => "backup",
        Action::Export => "export",
        Action::Notify => "notify",
        Action::Report => "report",
    }
}

fn summarize(job: &Job) -> String {
    let state = match job.action {
        Action::Backup | Action::Notify if job.retries > 0 => "retrying",
        Action::Cleanup if job.manual => "manual-cleanup",
        Action::Export | Action::Report if job.urgent => "active-high",
        Action::Sync => "active-low",
        _ if job.blocked => "blocked",
        _ => "pending-low",
    };

    let mut extras = Vec::new();
    if job.manual {
        extras.push("manual");
    }
    if job.retries > 0 {
        extras.push("retry");
    }

    if extras.is_empty() {
        format!("{} => {}: {}", action_name(&job.action), state, job.label)
    } else {
        format!(
            "{} => {}: {} [{}]",
            action_name(&job.action),
            state,
            job.label,
            extras.join(",")
        )
    }
}

fn main() {
    let jobs = [
        Job {
            action: Action::Backup,
            urgent: true,
            blocked: true,
