        },
        Job {
            action: Action::Notify,
            urgent: false,
            blocked: true,
            manual: false,
            retries: 1,
            label: "email-blast",
        },
        Job {
            action: Action::Report,
            urgent: true,
            blocked: false,
            manual: true,
            retries: 0,
            label: "monthly-report",
        },
    ];

    for job in jobs {
        println!("{}", summarize(&job));
    }
}
