pub fn parse_record(line: &str) -> Result<Record, String> {
    let mut id = None;
    let mut kind = None;
    let mut value = None;
    let mut tags: Vec<String> = Vec::new();

    for part in line.split('|') {
        let Some((key, raw_val)) = part.split_once('=') else {
            continue;
