            }
            "tags" => {
                tags = raw_val
                    .split(',')
                    .filter(|s| !s.is_empty())
                    .map(|s| s.to_string())
                    .collect();
            }
            _ => {}
        }
    }

    let id = id.ok_or_else(|| "missing id".to_string())?;
    let kind = kind.ok_or_else(|| "missing kind".to_string())?;
    let value = value.unwrap_or(0);

    Ok(Record { id, kind, value, tags })
}

