    "src/lib.rs": "#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Role {
    Guest,
    Member,
    Moderator,
    Admin,
    Auditor,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Route {
    Home,
    Billing,
    AdminPanel,
    AuditLog,
    Support,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Action {
    View,
    Edit,
    Refund,
    BanUser,
    Export,
}

pub fn decide(role: Role, route: Route, action: Action, suspended: bool) -> &'static str {
    if suspended {
        return match route {
            Route::Home => "read-only",
            _ => "deny",
        };
    }

    match role {
        Role::Guest => match route {
            Route::Home => "allow",
            Route::Support => "allow",
            _ => "deny",
        },
        Role::Member => match route {
            Route::Home => "allow",
            Route::Support => "allow",
            Route::Billing => match action {
                Action::View => "allow",
                _ => "deny",
            },
            _ => "deny",
        },
        Role::Moderator => match route {
            Route::Home | Route::Support => "allow",
            Route::AdminPanel => match action {
                Action::BanUser => "allow",
                _ => "deny",
            },
            _ => "deny",
        },
        Role::Admin => match route {
            Route::Home | Route::Support | Route::Billing | Route::AdminPanel => "allow",
            Route::AuditLog => "deny",
        },
        Role::Auditor => match route {
            Route::AuditLog => "deny",
            Route::Home => "allow",
