pub fn rank_entries(entries: &[Entry]) -> Vec<RankedEntry> {
    let mut by_id: HashMap<&'static str, Entry> = HashMap::new();
    for e in entries {
        by_id.insert(e.id, e.clone());
    }

    let mut merged: Vec<Entry> = by_id.into_values().collect();
    merged.sort_by(|a, b| {
        b.score
            .cmp(&a.score)
            .then_with(|| a.id.cmp(&b.id))
    });

    merged
        .into_iter()
        .enumerate()
        .map(|(i, e)| RankedEntry {
            rank: i + 1,
            id: e.id,
            score: e.score,
            wins: e.wins,
            penalty: e.penalty,
        })
        .collect()
}

