#[derive(Clone, Debug)]
pub struct SaleRecord<'a> {
    pub rep: &'a str,
    pub customer: &'a str,
    pub amount_cents: i32,
    pub refunded: bool,
    pub week: u8,
}

pub fn weekly_summary(records: &[SaleRecord], week: u8) -> String {
    let mut grouped: HashMap<&str, (i32, usize, usize)> = HashMap::new();

    for r in records {
        if r.week != week {
            continue;
        }

        let entry = grouped.entry(r.rep).or_insert((0, 0, 0));
        entry.0 += r.amount_cents;
        entry.1 += 1;
        if !r.customer.is_empty() {
            entry.2 += 1;
        }
    }

    let mut rows: Vec<_> = grouped.into_iter().collect();
    rows.sort_by(|a, b| a.0.cmp(b.0));

    let mut out = format!("Week {} summary\n", week);
    let mut grand_total = 0;
    let mut total_orders = 0;
    let mut all_customers: HashSet<&str> = HashSet::new();

    for (rep, (sales, orders, customers)) in rows {
        grand_total += sales;
        total_orders += orders;
        all_customers.insert(rep);
        out.push_str(&format!("{}: ${}.{:02} from {} orders, {} customers\n", rep, sales / 100, sales % 100, orders, customers));
    }

    out.push_str(&format!("TOTAL: ${}.{:02} across {} orders, {} customers", grand_total / 100, grand_total % 100, total_orders, all_customers.len()));
    out
}

