#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RankedPlayer {
    pub rank: usize,
    pub player: &'static str,
    pub score: u32,
    pub wins: u32,
    pub penalty: u32,
    pub played_at: u32,
}

pub fn leaderboard(records: &[MatchRecord]) -> Vec<RankedPlayer> {
    let mut rows = records.to_vec();
    rows.sort_by(|a, b| {
        b.score
            .cmp(&a.score)
            .then_with(|| a.player.cmp(&b.player))
    });

    let mut out = Vec::new();
    for (idx, r) in rows.into_iter().enumerate() {
        out.push(RankedPlayer {
            rank: idx + 1,
            player: r.player,
            score: r.score,
            wins: r.wins,
            penalty: r.penalty,
            played_at: r.played_at,
        });
    }
    out
}

