    "src/lib.rs": "#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Record {
    pub id: u32,
    pub kind: String,
    pub tags: Vec<(String, String)>,
}

pub fn parse_records(input: &str) -> Result<Vec<Record>, String> {
    let mut out = Vec::new();
    for (idx, raw) in input.lines().enumerate() {
        let line = raw.trim();
        if line.is_empty() {
            continue;
        }
        out.push(parse_line(line).map_err(|e| format!("line {}: {}", idx + 1, e))?);
    }
    Ok(out)
}

fn parse_line(line: &str) -> Result<Record, String> {
    let mut id = 0u32;
    let mut kind = String::new();
    let mut tags = Vec::new();

    for part in line.split('|') {
        let mut kv = part.splitn(2, '=');
        let key = kv.next().unwrap_or("").trim();
        let value = kv.next().unwrap_or("").trim();
        match key {
            "id" => id = value.parse().map_err(|_| "invalid id")?,
            "kind" => kind = value.to_string(),
            "tags" => {
                for item in value.split(',') {
                    if item.is_empty() {
                        continue;
                    }
                    let mut tv = item.splitn(2, ':');
                    let t = tv.next().unwrap_or("").trim();
                    let v = tv.next().unwrap_or("").trim();
                    tags.push((t.to_string(), v.to_string()));
                }
            }
            _ => {}
        }
    }

    Ok(Record { id, kind, tags })
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn parses_valid_records() {
        let input = "id=1|kind=alpha|tags=env:prod,team:core\nid=2|kind=beta|tags=env:dev";
        let got = parse_records(input).unwrap();
        assert_eq!(got.len(), 2);
        assert_eq!(got[0].id, 1);
