        b.score.cmp(&a.score)
            .then_with(|| a.player.cmp(&b.player))
    });

    merged
        .into_iter()
        .enumerate()
        .map(|(idx, row)| RankedRow {
            rank: idx + 1,
            player: row.player,
            score: row.score,
            solved: row.solved,
            penalty: row.penalty,
        })
        .collect()
}

