    pub retries: Option<u8>,
    pub use_tls: Option<bool>,
}

impl Config {
    pub fn with_endpoint(mut self, v: &str) -> Self {
        self.endpoint = Some(v.to_string());
        self
    }
    pub fn with_token(mut self, v: &str) -> Self {
        self.token = Some(v.to_string());
        self
    }
