    use super::*;

    #[test]
    fn suspended_is_denied_everywhere() {
        let reqs = [
            Request::ViewPage,
            Request::EditPage,
            Request::DeletePage,
            Request::ViewAudit,
            Request::ExportData,
            Request::BanUser,
        ];
        for env in [Env::Prod, Env::Staging] {
            for req in reqs {
                assert_eq!(route(Role::Suspended, env, req), "deny", "env={env:?} req={req:?}");
