fn build_report(rows: &[Record], regions: &[&str], depts: &[&str], min_amount: i32) -> String {
    let mut dept_totals: BTreeMap<&str, BTreeMap<&str, (usize, i32)>> = BTreeMap::new();
    let mut region_totals: BTreeMap<&str, (usize, i32)> = BTreeMap::new();
