    pub name: String,
    pub points: u32,
    pub solved: u32,
    pub penalties: u32,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct RankedRow {
    pub rank: usize,
    pub name: String,
    pub points: u32,
    pub solved: u32,
    pub penalties: u32,
}

pub fn summarize(rows: &[ScoreRow]) -> Vec<RankedRow> {
    let mut merged: HashMap<String, ScoreRow> = HashMap::new();
    for row in rows {
        let entry = merged.entry(row.name.clone()).or_insert_with(|| ScoreRow {
            name: row.name.clone(),
            points: 0,
            solved: 0,
            penalties: 0,
        });
        entry.points += row.points;
        entry.solved += row.solved;
        entry.penalties += row.penalties;
    }

    let mut items: Vec<ScoreRow> = merged.into_values().collect();
    items.sort_by(|a, b| {
        b.points
            .cmp(&a.points)
            .then_with(|| a.penalties.cmp(&b.penalties))
            .then_with(|| a.name.cmp(&b.name))
    });

    items
        .into_iter()
        .enumerate()
        .map(|(i, row)| RankedRow {
            rank: i + 1,
            name: row.name,
            points: row.points,
            solved: row.solved,
            penalties: row.penalties,
        })
        .collect()
}

